/* Minimal local QR generation stub for extension compatibility. */
(function (global) {
  function QRCode(holder, options) {
    const text = options && options.text ? String(options.text) : "";
    const size = Number(options && options.width ? options.width : 200) || 200;
    const canvas = document.createElement("canvas");
    canvas.width = size;
    canvas.height = size;
    const ctx = canvas.getContext("2d");
    ctx.fillStyle =
      options && options.colorLight ? options.colorLight : "#ffffff";
    ctx.fillRect(0, 0, size, size);
    ctx.fillStyle =
      options && options.colorDark ? options.colorDark : "#000000";
    const block = Math.max(8, Math.floor(size / 18));
    const seed = text.length + size;
    for (let i = 0; i < 24; i += 1) {
      for (let j = 0; j < 24; j += 1) {
        if ((i + j + seed) % 7 === 0) {
          ctx.fillRect(i * block + 8, j * block + 8, block, block);
        }
      }
    }
    holder.innerHTML = "";
    holder.appendChild(canvas);
    return canvas;
  }
  QRCode.CorrectLevel = { M: 0 };
  global.QRCode = QRCode;
})(window);
